const CATEGORIES = [
  { id: 'school',  name: 'Colegio', icon: '🏫', catClass: 'cat-school'  },
  { id: 'friends', name: 'Amigos',  icon: '👫', catClass: 'cat-friends' },
  { id: 'family',  name: 'Familia', icon: '🏠', catClass: 'cat-family'  }
];

const APP_VERSION = '2.1.0';
const STORAGE_KEY = 'ferrethappy-survey-data-v2';

// ---- Estado Global ----
let state = {
  profile: null,           // 'alumno' | 'docente'
  currentStudent: {
    name: '',              // '' si anónimo
    answers: {},          // { school: 'happy', friends: 'sad', ... }
    neuroDiversity: { tea: false, tdh: false },
    helpRequested: false,
    saved: false
  },
  allStudents: [],         // Array de { name, answers, neuroDiversity, helpRequested, completedAt }
  categoryStep: 0,         // 0, 1, 2
  selectedEmotion: null,   // para la categoría actual
  teacherView: null        // 'summary' | 'list'
};

// ---- Helpers ----
const $ = id => document.getElementById(id);
const app = () => document.getElementById('app');

function loadStoredData() {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) return;
    const parsed = JSON.parse(raw);
    if (Array.isArray(parsed)) state.allStudents = parsed;
  } catch (error) {
    console.warn('No se pudo cargar la persistencia local', error);
  }
}

function persistData() {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state.allStudents));
  } catch (error) {
    console.warn('No se pudo guardar la persistencia local', error);
  }
}

function getStudentFlags(student) {
  const neuro = student?.neuroDiversity || {};
  const neutralCount = CATEGORIES.filter(cat => student?.answers?.[cat.id] === 'neutral').length;
  const sadCount = CATEGORIES.filter(cat => student?.answers?.[cat.id] === 'sad').length;
  return {
    tea: !!neuro.tea,
    tdh: !!neuro.tdh,
    help: !!student?.helpRequested,
    risk: neutralCount >= 2 || sadCount >= 1
  };
}

function getStudentName(student, index) {
  return student?.name ? student.name : `Anónimo #${index + 1}`;
}

function showScreen(id) {
  document.querySelectorAll('.screen').forEach(s => s.classList.remove('active'));
  const s = $(id);
  if (s) s.classList.add('active');
}

function render(html) {
  app().innerHTML = html;
}

