// ---- DOCENTE: Resumen ----
function screenDocenteResumen() {
  state.teacherView = 'summary';
  const total = state.allStudents.length;

  const catRows = CATEGORIES.map(cat => {
    const counts = { sad: 0, neutral: 0, happy: 0 };
    state.allStudents.forEach(s => {
      const ans = s.answers[cat.id];
      if (ans) counts[ans]++;
    });
    const pills = Object.entries(counts).map(([key, n]) =>
      n > 0 ? `<span class="emotion-pill ${key}">${EMOTIONS[key].smallSvg} ${EMOTIONS[key].label}: <strong>${n}</strong></span>` : ''
    ).join('');
    return `
      <div class="summary-cat-row">
        <span class="summary-cat-name">${cat.icon} ${cat.name}</span>
        <div class="summary-emotion-counts">${pills || '<span class="anon-badge">Sin respuestas</span>'}</div>
      </div>`;
  }).join('');

  render(`
    <div class="screen active" id="screen-doc-resumen">
      <div class="card" style="max-width:520px;width:100%">
        <h2>📊 Resumen de la encuesta</h2>
        <div class="summary-box">
          <div class="summary-stat">${total}</div>
          <div class="summary-stat-label">alumno${total !== 1 ? 's' : ''} respondió la encuesta hoy</div>
          <div class="summary-cats">${total === 0 ? '<p style="color:var(--text-light)">Aún no hay respuestas registradas.</p>' : catRows}</div>
        </div>
        <div class="btn-group">
          <button class="btn btn-success" onclick="grabarHTML()">💾 Grabar resultado</button>
          <button class="btn btn-danger" onclick="screenHome()">✗ Salir sin guardar</button>
        </div>
        <div class="spacer-sm"></div>
        <button class="btn btn-ghost btn-full" onclick="screenDocenteOpciones()">← Volver</button>
      </div>
    </div>
  `);
}

// ---- DOCENTE: Lista de alumnos ----
function screenDocenteLista() {
  state.teacherView = 'list';
  const rows = state.allStudents.length === 0
    ? `<tr><td colspan="7" style="text-align:center;color:var(--text-light);padding:20px">Aún no hay alumnos encuestados.</td></tr>`
    : state.allStudents.map((s, i) => {
        const flags = getStudentFlags(s);
        const name = s.name ? s.name : `<span class="anon-badge">Anónimo #${i+1}</span>`;
        const cells = CATEGORIES.map(cat => {
          const emo = s.answers[cat.id];
          return `<td>${emo ? EMOTIONS[emo].smallSvg : '-'}</td>`;
        }).join('');
        const neuroCell = `<td>${flags.tea || flags.tdh ? `${flags.tea ? '<span class="alert-badge alert-purple">TEA</span>' : ''}${flags.tea && flags.tdh ? ' ' : ''}${flags.tdh ? '<span class="alert-badge alert-purple">TDH</span>' : ''}` : '-'}</td>`;
        const riskCell = `<td>${flags.risk ? '<span class="alert-badge alert-coral">Riesgo</span>' : '-'}</td>`;
        const helpCell = `<td>${flags.help ? '<span class="alert-badge alert-blue">Ayuda</span>' : '-'}</td>`;
        return `<tr><td>${name}</td>${cells}${neuroCell}${riskCell}${helpCell}</tr>`;
      }).join('');

  render(`
    <div class="screen active" id="screen-doc-lista">
      <div class="card" style="max-width:660px;width:100%">
        <h2>📋 Lista de alumnos encuestados</h2>
        <p>${state.allStudents.length} alumno${state.allStudents.length !== 1 ? 's' : ''} registrado${state.allStudents.length !== 1 ? 's' : ''}</p>
        <div class="student-table-wrap">
          <table class="student-table">
            <thead>
              <tr>
                <th>Alumno</th>
                <th>🏫 Colegio</th>
                <th>👫 Amigos</th>
                <th>🏠 Familia</th>
                <th>TEA/TDH</th>
                <th>Riesgo</th>
                <th>Ayuda</th>
              </tr>
            </thead>
            <tbody>${rows}</tbody>
          </table>
        </div>
        <div class="btn-group">
          <button class="btn btn-success" onclick="grabarHTML()">💾 Grabar resultado</button>
          <button class="btn btn-danger" onclick="screenHome()">✗ Salir sin guardar</button>
        </div>
        <div class="spacer-sm"></div>
        <button class="btn btn-ghost btn-full" onclick="screenDocenteOpciones()">← Volver</button>
      </div>
    </div>
  `);
}

// ---- GRABAR HTML ----
function grabarHTML() {
  const total = state.allStudents.length;
  const now = new Date();
  const dateStr = now.toLocaleDateString('es-CL', { day:'2-digit', month:'2-digit', year:'numeric' });
  const timeStr = now.toLocaleTimeString('es-CL', { hour:'2-digit', minute:'2-digit' });

  // Build summary counts
  const catSummary = CATEGORIES.map(cat => {
    const counts = { sad: 0, neutral: 0, happy: 0 };
    state.allStudents.forEach(s => { const a = s.answers[cat.id]; if (a) counts[a]++; });
    return { cat, counts };
  });

  const summaryRows = catSummary.map(({ cat, counts }) =>
    `<tr>
      <td><b>${cat.icon} ${cat.name}</b></td>
      <td>${counts.sad}</td>
      <td>${counts.neutral}</td>
      <td>${counts.happy}</td>
    </tr>`
  ).join('');

  // Totals row
  const totalSad     = catSummary.reduce((a, { counts }) => a + counts.sad, 0);
  const totalNeutral = catSummary.reduce((a, { counts }) => a + counts.neutral, 0);
  const totalHappy   = catSummary.reduce((a, { counts }) => a + counts.happy, 0);

  const studentRows = state.allStudents.map((s, i) => {
    const name = getStudentName(s, i);
    const flags = getStudentFlags(s);
    const cells = CATEGORIES.map(cat => {
      const emo = s.answers[cat.id];
      return `<td style="text-align:center">${emo ? EMOTIONS[emo].label : '-'}</td>`;
    }).join('');
    const teaCell = `<td style="text-align:center">${flags.tea || flags.tdh ? `${flags.tea ? 'TEA' : ''}${flags.tea && flags.tdh ? ' / ' : ''}${flags.tdh ? 'TDH' : ''}` : '-'}</td>`;
    const riskCell = `<td style="text-align:center">${flags.risk ? '⚠️ Sí' : '—'}</td>`;
    const helpCell = `<td style="text-align:center">${flags.help ? '✋ Sí' : '—'}</td>`;
    return `<tr><td>${name}</td>${cells}${teaCell}${riskCell}${helpCell}</tr>`;
  }).join('');

  const html = `<!DOCTYPE html>
<html lang="es">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>EmocionKids - Resultado ${dateStr}</title>
<style>
  body { font-family: 'Segoe UI', Arial, sans-serif; background: #f5f0ff; color: #3A3560; padding: 30px; }
  h1 { color: #9B7EC8; font-size: 2rem; margin:0 0 8px; }
  h2 { color: #4ABFA8; margin-top: 30px; margin-bottom: 8px; }
  .header { display:flex; align-items:flex-start; gap:16px; margin-bottom:24px; flex-wrap:wrap; }
  .badge { background: #9B7EC8; color: #fff; border-radius: 50px; padding: 6px 18px; font-weight: 700; display:inline-block; }
  table { border-collapse: collapse; width: 100%; max-width: 700px; margin-top: 12px; border-radius: 10px; overflow: hidden; box-shadow: 0 2px 10px rgba(100,80,160,0.10); }
  th { background: #9B7EC8; color: #fff; padding: 11px 16px; text-align: left; font-size: 0.95rem; }
  td { padding: 9px 16px; border-bottom: 1px solid #e4d4f4; font-size: 0.92rem; }
  tr:nth-child(even) td { background: #f5f0ff; }
  .total-row td { background: #d8cdf0 !important; font-weight: 800; border-top: 2.5px solid #9B7EC8; font-size: 0.95rem; }
  .stat-row { display: flex; align-items: baseline; gap: 12px; margin: 6px 0 18px; }
  .stat { font-size: 2.6rem; font-weight: 900; color: #9B7EC8; line-height: 1; }
  .stat-label { font-size: 1.05rem; color: #5A5380; font-weight: 600; }
  .table-blue th { background: #3A7EC8; }
  .table-blue tr:nth-child(even) td { background: #eef4ff; }
  footer { margin-top: 40px; font-size: 0.85rem; color: #8E8DB0; border-top: 1px solid #e4d4f4; padding-top: 16px; }
</style>
</head>
<body>
<div class="header">
  <div>
    <h1>🐾 EmocionKids — Resultado de encuesta</h1>
    <span class="badge">Fecha: ${dateStr} — Hora: ${timeStr}</span>
  </div>
</div>

<h2>📊 Resumen General</h2>
<div class="stat-row">
  <span class="stat">${total}</span>
  <span class="stat-label">alumno${total!==1?'s':''} respondió${total!==1?'n':''} la encuesta</span>
</div>

<table>
  <thead>
    <tr>
      <th>Categoría</th>
      <th>😢 Triste</th>
      <th>😐 No sé</th>
      <th>😊 Contento</th>
    </tr>
  </thead>
  <tbody>
    ${summaryRows}
    <tr class="total-row">
      <td><b>Total</b></td>
      <td><b>${totalSad}</b></td>
      <td><b>${totalNeutral}</b></td>
      <td><b>${totalHappy}</b></td>
    </tr>
  </tbody>
</table>

<h2>📋 Lista de alumnos encuestados</h2>
<table>
  <thead>
    <tr>
      <th>Alumno</th>
      <th>🏫 Colegio</th>
      <th>👫 Amigos</th>
      <th>🏠 Familia</th>
      <th>TEA/TDH</th>
      <th>Riesgo</th>
      <th>Ayuda</th>
    </tr>
  </thead>
  <tbody>${studentRows || '<tr><td colspan="7">Sin datos</td></tr>'}</tbody>
</table>

<footer>Generado por FerretHappy v${APP_VERSION} · ${dateStr} ${timeStr}</footer>
</body>
</html>`;

  const blob = new Blob([html], { type: 'text/html' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `FerretHappy_${dateStr.replace(/\//g, '-')}.html`;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);

  // Show confirmation briefly
  persistData();

  const msg = document.createElement('div');
  msg.textContent = '✅ ¡Archivo guardado!';
  msg.style.cssText = 'position:fixed;bottom:24px;left:50%;transform:translateX(-50%);background:#4ABFA8;color:#fff;padding:12px 28px;border-radius:50px;font-weight:800;font-size:1rem;box-shadow:0 4px 18px rgba(74,191,168,0.4);z-index:9999';
  document.body.appendChild(msg);
  setTimeout(() => msg.remove(), 2800);
}

function finalizarEncuesta() {
  saveCurrentStudent();
  grabarHTML();
  screenHome();
}

// ---- Keyboard accessibility for profile cards ----
document.addEventListener('keydown', e => {
  if (e.key === 'Enter' && document.activeElement.classList.contains('profile-card')) {
    document.activeElement.click();
  }
});

// ---- Init ----
loadStoredData();
screenHome();
